char* modify_filename(const char* filename) {
    static char new_filename[256];
    const char *dot = strrchr(filename, '.');
    int digit_count = 0;
    char file_type;

    for (const char *p = filename; *p; ++p)
        if (isdigit(*p)) digit_count++;

    if (dot && dot != filename && *(dot + 1))
        file_type = *(dot + 1);
    else
        file_type = *filename ? *filename : 'x';

    if (dot && dot != filename) {
        size_t base_len = dot - filename;
        strncpy(new_filename, filename, base_len);
        new_filename[base_len] = '\0';
    } else
        strcpy(new_filename, filename);

    char ext[16];
    sprintf(ext, ".%d%c", digit_count, file_type);
    strcat(new_filename, ext);

    return new_filename;
}
