    char subkeyPath[256];
    snprintf(subkeyPath, sizeof(subkeyPath), "SOFTWARE\\JavaSoft\\Java Runtime Environment\\%s", version);
    free(version);

    result = RegOpenKeyEx(HKEY_LOCAL_MACHINE, subkeyPath, 0, KEY_READ, &hSubKey);
    if (result != ERROR_SUCCESS) return NULL;

    result = RegQueryValueEx(hSubKey, "JavaHome", NULL, &type, NULL, &size);
    if (result != ERROR_SUCCESS || type != REG_SZ) {
        RegCloseKey(hSubKey);
        return NULL;
    }
    javaHome = (LPSTR)malloc(size);
    result = RegQueryValueEx(hSubKey, "JavaHome", NULL, &type, (LPBYTE)javaHome, &size);
    RegCloseKey(hSubKey);
    if (result != ERROR_SUCCESS) {
        free(javaHome);
        return NULL;
    }

    return javaHome;
}
