void testSortedVectorSet() {
    std::vector<int> original;
    std::random_device rd;
    std::mt19937 gen(rd());
    std::uniform_int_distribution<> size_dist(0, 50);
    int size = size_dist(gen);

    std::uniform_int_distribution<> elem_dist(-100, 100);
    std::vector<int> temp;
    for (int i = 0; i < size; ++i) {
        temp.push_back(elem_dist(gen));
    }
    std::sort(temp.begin(), temp.end());
    auto last = std::unique(temp.begin(), temp.end());
    temp.erase(last, temp.end());
    original = temp;

    bool is_sorted = std::is_sorted(original.begin(), original.end());
    bool has_duplicates = std::unique(original.begin(), original.end()) != original.end();
    assert(is_sorted && !has_duplicates);

    std::vector<int> new_set;
    for (int elem : original) {
        auto it = std::lower_bound(new_set.begin(), new_set.end(), elem);
        if (it == new_set.end() || *it != elem) {
            new_set.insert(it, elem);
        }
    }

    assert(original == new_set);
}

