#include <cstring>
#include <unistd.h>
#include <sys/socket.h>
#include <netinet/in.h>
#include <arpa/inet.h>

class RobotClient {
private:
    std::string ip;
    int port;
    int sock;
    bool connected;

public:
    RobotClient(const std::string& ip, int port) : ip(ip), port(port), sock(-1), connected(false) {}

    bool connect() {
        sock = socket(AF_INET, SOCK_STREAM, 0);
        if (sock == -1) {
            perror("socket");
            return false;
        }

        sockaddr_in server_addr{};
        server_addr.sin_family = AF_INET;
        server_addr.sin_port = htons(port);

        if (inet_pton(AF_INET, ip.c_str(), &server_addr.sin_addr) <= 0) {
            perror("inet_pton");
            close(sock);
            return false;
        }

        if (::connect(sock, (struct sockaddr*)&server_addr, sizeof(server_addr)) < 0) {
            perror("connect");
            close(sock);
            return false;
        }

        connected = true;
        return true;
    }

    bool sendCommand(const std::string& command) {
        if (!connected) return false;

        ssize_t bytes_sent = send(sock, command.c_str(), command.size(), 0);
        if (bytes_sent < 0) {
            perror("send");
            disconnect();
            return false;
        }
        return true;
    }

    std::string receiveResponse() {
        if (!connected) return "";

        char buffer[1024];
        std::string response;
        ssize_t bytes_received;

        while ((bytes_received = recv(sock, buffer, sizeof(buffer), 0)) > 0) {
            response.append(buffer, bytes_received);
        }

        if (bytes_received < 0) {
            perror("recv");
            disconnect();
        } else if (bytes_received == 0) {
            disconnect();
        }

        return response;
    }

    void disconnect() {
        if (connected) {
            close(sock);
            connected = false;
        }
    }

    bool isConnected() const { return connected; }

    ~RobotClient() { disconnect(); }
};

int main() {
    std::string ip;
    int port;

    std::cout << "Enter server IP: ";
    std::cin >> ip;
    std::cout << "Enter server port: ";
    std::cin >> port;

    RobotClient client(ip, port);
    if (!client.connect()) {
        std::cerr << "Connection failed\n";
        return 1;
    }

    std::cin.ignore();
    while (client.isConnected()) {
        std::string cmd;
        std::cout << "Enter command: ";
        std::getline(std::cin, cmd);

        if (cmd == "exit") break;

        if (!client.sendCommand(cmd)) {
            std::cerr << "Command send failed\n";
            break;
        }

        std::string response = client.receiveResponse();
        if (response.empty()) {
            std::cerr << "Connection lost\n";
            break;
        }
        std::cout << "Response: " << response << "\n";
    }

    return 0;
}
