char *execute_commands(const Config *config) {
    char cmd[4096];
    static char output[65536];
    FILE *fp;

    if (strcmp(config->protocol, "SSH") == 0) {
        snprintf(cmd, sizeof(cmd), "ssh -o StrictHostKeyChecking=no %s@%s \"", config->user, config->host);
        for (int i = 0; i < config->num_commands; ++i) {
            if (i > 0) strcat(cmd, "; ");
            strcat(cmd, config->commands[i]);
        }
        strcat(cmd, "\"");
        fp = popen(cmd, "r");
    } else if (strcmp(config->protocol, "Telnet") == 0) {
        char *password = getpass("Enter Telnet password: ");
        char expect_cmd[8192];
        snprintf(expect_cmd, sizeof(expect_cmd),
            "expect -c 'spawn telnet %s %d; "
            "expect \"login:\"; send \"%s\\r\"; "
            "expect \"Password:\"; send \"%s\\r\"; ",
            config->host, config->port, config->user, password);
        for (int i = 0; i < config->num_commands; ++i) {
            strcat(expect_cmd, "expect {\"$ \"}; ");
            strcat(expect_cmd, "send \"");
            strcat(expect_cmd, config->commands[i]);
            strcat(expect_cmd, "\\r\"; ");
        }
        strcat(expect_cmd, "send \"exit\\r\"; expect eof'");
        fp = popen(expect_cmd, "r");
    } else {
        return NULL;
    }

    if (!fp) return NULL;
    size_t len = fread(output, 1, sizeof(output)-1, fp);
    output[len] = '\0';
    pclose(fp);
    return output;
}
