void ManageEntities(ComponentManager& componentManager) {
    static std::vector<Entity> activeEntities;

    auto newEntities = componentManager.GetNewEntities();
    activeEntities.insert(activeEntities.end(), newEntities.begin(), newEntities.end());

    std::vector<Entity> toDestroy;
    for (const auto& entity : activeEntities) {
        componentManager.Update(entity);
        if (rand() % 100 < 10) {
            toDestroy.push_back(entity);
        }
    }

    std::unordered_set<Entity> toDestroySet(toDestroy.begin(), toDestroy.end());
    for (const auto& entity : toDestroy) {
        componentManager.DestroyEntity(entity);
    }

    activeEntities.erase(
        std::remove_if(activeEntities.begin(), activeEntities.end(),
            [&toDestroySet](Entity e) { return toDestroySet.count(e); }),
        activeEntities.end()
    );
}
