    std::mt19937 gen(rd());
    std::uniform_real_distribution<> val_dist(0.0, 1.0);

    if (format == "CSR") {
        std::uniform_int_distribution<> col_dist(0, cols - 1);
        for (int i = 0; i < rows; ++i) {
            int start = outer_ptr[i];
            int end = outer_ptr[i + 1];
            for (int j = start; j < end; ++j) {
                inner_indices[j] = col_dist(gen);
                values[j] = val_dist(gen);
            }
        }
    } else if (format == "CSC") {
        std::uniform_int_distribution<> row_dist(0, rows - 1);
        for (int j = 0; j < cols; ++j) {
            int start = outer_ptr[j];
            int end = outer_ptr[j + 1];
            for (int k = start; k < end; ++k) {
                inner_indices[k] = row_dist(gen);
                values[k] = val_dist(gen);
            }
        }
    }
}

