    int num_vertices;
    int* degrees;
    int** heads;
};

template<typename Iterator>
AdjacencyList create_adjacency_list(Iterator begin, Iterator end) {
    int max_vertex = -1;
    for (Iterator it = begin; it != end; ++it) {
        int u = it->first;
        int v = it->second;
        if (u > max_vertex) max_vertex = u;
        if (v > max_vertex) max_vertex = v;
    }

    if (max_vertex == -1) {
        return {0, nullptr, nullptr};
    }

    int num_vertices = max_vertex + 1;
    int* degrees = new int[num_vertices]();

    for (Iterator it = begin; it != end; ++it) {
        int u = it->first;
        ++degrees[u];
    }

    int** heads = new int*[num_vertices];
    for (int i = 0; i < num_vertices; ++i) {
        if (degrees[i] > 0) {
            heads[i] = new int[degrees[i]];
        } else {
            heads[i] = nullptr;
        }
    }

    int* current = new int[num_vertices]();
    for (Iterator it = begin; it != end; ++it) {
        int u = it->first;
        int v = it->second;
        heads[u][current[u]++] = v;
    }
    delete[] current;

    return {num_vertices, degrees, heads};
}
