    *count = 0;
    if (!devices) return NULL;

    size_t num = 0;
    struct UPNPDev *current = devices;
    while (current) { num++; current = current->pNext; }

    char **descriptions = malloc(num * sizeof(char*));
    if (!descriptions) { freeUPNPDevlist(devices); return NULL; }

    current = devices;
    for (size_t i=0; i<num; i++) {
        descriptions[i] = strdup(current->descURL);
        if (!descriptions[i]) {
            for (size_t j=0; j<i; j++) free(descriptions[j]);
            free(descriptions);
            freeUPNPDevlist(devices);
            return NULL;
        }
        current = current->pNext;
    }

    freeUPNPDevlist(devices);
    *count = num;
    return descriptions;
}
