    char* data = (char*)arg;

    pthread_mutex_lock(&mutex);
    strncpy(shared_buffer, data, MAX_STR);
    printf("Copied: %s\n", shared_buffer);
    pthread_mutex_unlock(&mutex);

    return NULL;
}

int main() {
    pthread_t t1, t2;

    pthread_mutex_init(&mutex, NULL);

    pthread_create(&t1, NULL, thread_function, "Thread 1 message");
    pthread_create(&t2, NULL, thread_function, "Thread 2 text");

    pthread_join(t1, NULL);
    pthread_join(t2, NULL);

    pthread_mutex_destroy(&mutex);

    return 0;
