char* strip_whitespace(const char *str) {
    if (!str) return NULL;

    size_t count = 0;
    const char *p = str;
    while (*p) {
        if (!isspace((unsigned char)*p)) count++;
        p++;
    }

    char *result = malloc(count + 1);
    if (!result) return NULL;

    p = str;
    char *dest = result;
    while (*p) {
        if (!isspace((unsigned char)*p))
            *dest++ = *p;
        p++;
    }
    *dest = '\0';

    return result;
}
