TreeNode* buildTree(int n, int* c) {
    for (int i = 0; i < 2 * n; ++i)
        std::cin >> c[i];

    std::vector<TreeNode*> nodes(n);
    for (int i = 0; i < n; ++i)
        nodes[i] = new TreeNode(i);

    std::vector<bool> isChild(n, false);
    for (int i = 0; i < 2 * n; ++i) {
        int child = c[i];
        if (child != -1)
            isChild[child] = true;
    }

    int rootIdx = -1;
    for (int i = 0; i < n; ++i) {
        if (!isChild[i]) {
            rootIdx = i;
            break;
        }
    }

    for (int i = 0; i < n; ++i) {
        int left = c[2 * i];
        int right = c[2 * i + 1];
        nodes[i]->left = left != -1 ? nodes[left] : nullptr;
        nodes[i]->right = right != -1 ? nodes[right] : nullptr;
    }

    return nodes[rootIdx];
}

