bool verifyFramebufferContent(int x, int y, int width, int height, const void* expectedData, GLenum format, GLenum type) {
    GLint originalAlignment;
    glGetIntegerv(GL_PACK_ALIGNMENT, &originalAlignment);
    glPixelStorei(GL_PACK_ALIGNMENT, 1);

    int components;
    switch(format) {
        case GL_RGBA: components = 4; break;
        case GL_RGB:  components = 3; break;
        case GL_RED:  components = 1; break;
        default:      return false;
    }

    size_t typeSize;
    switch(type) {
        case GL_UNSIGNED_BYTE:
        case GL_BYTE:  typeSize = 1; break;
        case GL_FLOAT:
        case GL_INT:   typeSize = 4; break;
        default:       return false;
    }

    size_t bufferSize = width * height * components * typeSize;
    unsigned char* buffer = new unsigned char[bufferSize];
    glReadPixels(x, y, width, height, format, type, buffer);
    glPixelStorei(GL_PACK_ALIGNMENT, originalAlignment);

    bool match = (memcmp(buffer, expectedData, bufferSize) == 0);
    delete[] buffer;
    return match;
}
