bool checkTensorData(const string& csv, const Tensor& tensor) {
    vector<string> tokens;
    istringstream ss(csv);
    string token;

    while (getline(ss, token, ',')) {
        size_t start = token.find_first_not_of(" \t\n\r");
        if (start == string::npos) tokens.push_back("");
        else {
            size_t end = token.find_last_not_of(" \t\n\r");
            tokens.push_back(token.substr(start, end - start + 1));
        }
    }

    if (tokens.size() != tensor.num_elements()) return false;

    switch(tensor.dtype()) {
        case DataType::INT32: {
            auto data = tensor.data<int32_t>();
            for (size_t i = 0; i < tokens.size(); ++i) {
                try {
                    if (stoi(tokens[i]) != data[i]) return false;
                } catch (...) { return false; }
            }
            break;
        }
        case DataType::FLOAT: {
            auto data = tensor.data<float>();
            for (size_t i = 0; i < tokens.size(); ++i) {
                try {
                    if (stof(tokens[i]) != data[i]) return false;
                } catch (...) { return false; }
            }
            break;
        }
        case DataType::DOUBLE: {
            auto data = tensor.data<double>();
            for (size_t i = 0; i < tokens.size(); ++i) {
                try {
                    if (stod(tokens[i]) != data[i]) return false;
                } catch (...) { return false; }
            }
            break;
        }
        case DataType::BOOL: {
            auto data = tensor.data<bool>();
            for (size_t i = 0; i < tokens.size(); ++i) {
                string val = tokens[i];
                transform(val.begin(), val.end(), val.begin(), ::tolower);
                if ((val != "true" && val != "1" && val != "false" && val != "0") ||
                    (data[i] && val != "true" && val != "1") ||
                    (!data[i] && val != "false" && val != "0"))
                    return false;
            }
            break;
        }
        default: return false;
    }
    return true;
}

