public static byte[] generatePPM(PageDocument doc, int pageNumber) {
    try {
        Page page = doc.getPage(pageNumber);
        int displayWidth = doc.getDisplayWidth();
        int displayHeight = doc.getDisplayHeight();
        BufferedImage image = page.getImage().getScaledInstance(displayWidth, displayHeight, Image.SCALE_SMOOTH);
        BufferedImage scaledImage = new BufferedImage(displayWidth, displayHeight, BufferedImage.TYPE_INT_RGB);
        scaledImage.getGraphics().drawImage(image, 0, 0, null);

        ByteArrayOutputStream byteStream = new ByteArrayOutputStream();
        String header = String.format("P6\n%d %d\n255\n", displayWidth, displayHeight);
        byteStream.write(header.getBytes(StandardCharsets.US_ASCII));

        for (int y = 0; y < displayHeight; y++) {
            for (int x = 0; x < displayWidth; x++) {
                int rgb = scaledImage.getRGB(x, y);
                byteStream.write((byte) ((rgb >> 16) & 0xFF));
                byteStream.write((byte) ((rgb >> 8) & 0xFF));
                byteStream.write((byte) (rgb & 0xFF));
            }
        }

        return byteStream.toByteArray();
    } catch (IOException e) {
        throw new RuntimeException(e);
    }
}

