std::mutex queue_mutex;
std::condition_variable queue_cond;
std::queue<std::pair<int, std::string>> message_queue;

void worker_thread() {
    while (true) {
        std::unique_lock<std::mutex> lock(queue_mutex);
        queue_cond.wait(lock, []{ return !message_queue.empty(); });
        auto [client_socket, message] = message_queue.front();
        message_queue.pop();
        lock.unlock();

        printf("Received from %d: %s\n", client_socket, message.c_str());
    }
}

void handle_client(int client_socket) {
    char buffer[1024];
    while (true) {
        ssize_t bytes_read = read(client_socket, buffer, sizeof(buffer));
        if (bytes_read <= 0) {
            close(client_socket);
            printf("Connection closed: %d\n", client_socket);
            return;
        }
        std::lock_guard<std::mutex> lock(queue_mutex);
        message_queue.emplace(client_socket, std::string(buffer, bytes_read));
        queue_cond.notify_one();
    }
}

