        if (ex->ExceptionRecord->ExceptionCode == EXCEPTION_ACCESS_VIOLATION) {
            ULONG_PTR faultAddr = (ULONG_PTR)ex->ExceptionRecord->ExceptionInformation[1];
            bytesRead = faultAddr - (ULONG_PTR)block;
        }
    }

    VirtualFree(block, 0, MEM_RELEASE);
    free(buffer);

    return bytesRead;
