unsigned char *decompress_jpeg(unsigned char *jpeg_buffer, unsigned long jpeg_size, int *height, int *width, int *bytes_per_pixel, int *line_size) {
    struct jpeg_decompress_struct cinfo;
    struct jpeg_error_mgr jerr;
    JSAMPARRAY buffer;
    unsigned char *pixels = NULL;

    cinfo.err = jpeg_std_error(&jerr);
    jpeg_create_decompress(&cinfo);
    jpeg_mem_src(&cinfo, jpeg_buffer, jpeg_size);
    jpeg_read_header(&cinfo, TRUE);
    cinfo.out_color_space = JCS_RGB;

    jpeg_calc_output_dimensions(&cinfo);
    jpeg_start_decompress(&cinfo);

    *height = cinfo.output_height;
    *width = cinfo.output_width;
    *bytes_per_pixel = cinfo.output_components;
    *line_size = cinfo.output_width * (*bytes_per_pixel);

    pixels = (unsigned char *)malloc((*height) * (*line_size));
    if (!pixels) {
        jpeg_abort_decompress(&cinfo);
        jpeg_destroy_decompress(&cinfo);
        return NULL;
    }

    buffer = (*cinfo.mem->alloc_sarray)((j_common_ptr)&cinfo, JPOOL_IMAGE, *line_size, 1);
    unsigned char *current_row = pixels;

    while (cinfo.output_scanline < cinfo.output_height) {
        jpeg_read_scanlines(&cinfo, buffer, 1);
        memcpy(current_row, buffer[0], *line_size);
        current_row += *line_size;
    }

    jpeg_finish_decompress(&cinfo);
    jpeg_destroy_decompress(&cinfo);

    return pixels;
}
