void generateQueryString(char* query, const char* url, int depth, bool nonCgi, bool hasFilename, bool hasPermalink, bool hasRandomScore) {
    const char* hostStart = strstr(url, "://");
    hostStart = hostStart ? hostStart + 3 : url;

    const char* hostEnd = hostStart;
    while (*hostEnd && *hostEnd != '/' && *hostEnd != '?' && *hostEnd != '#') ++hostEnd;

    char host[256];
    int hostLen = hostEnd - hostStart;
    if (hostLen >= 255) hostLen = 255;
    strncpy(host, hostStart, hostLen);
    host[hostLen] = '\0';

    sprintf(query, "host=%s&pathDepth=%d&nonCgi=%d&hasFilename=%d&hasPermalink=%d&randomScore=%d", 
            host, depth, nonCgi, hasFilename, hasPermalink, hasRandomScore);
}
