FileMeta* create_fd_array(int count, ...) {
    va_list args;
    va_start(args, count);
    FileMeta* array = NULL;
    for (int i = 0; i < count; i++) {
        int fd = va_arg(args, int);
        FileMeta* temp = realloc(array, (i + 1) * sizeof(FileMeta));
        if (!temp) {
            free(array);
            va_end(args);
            return NULL;
