        array = temp;
        struct stat statbuf;
        fstat(fd, &statbuf);
        array[i].fd = fd;
        array[i].mode = statbuf.st_mode;
        array[i].flags = fcntl(fd, F_GETFL);
        array[i].offset = lseek(fd, 0, SEEK_CUR);
    }
    va_end(args);
    return array;
