std::map<int, int> countFrequency(const std::vector<int>& list) {
    std::map<int, int> freqMap;
    if (list.empty()) return freqMap;

    auto [minIt, maxIt] = std::minmax_element(list.begin(), list.end());
    int min = *minIt, max = *maxIt;
    std::vector<int> counts(max - min + 1, 0);

    for (int num : list) ++counts[num - min];

    for (int i = 0; i < counts.size(); ++i)
        if (counts[i]) freqMap[min + i] = counts[i];

    return freqMap;
}

