#include <stdlib.h>
#include <string.h>

int main() {
    FILE *file = fopen("test.txt", "w+");
    if (!file) {
        perror("Failed to open file");
        exit(EXIT_FAILURE);
    }

    const char *message = "Hello, World!";
    size_t message_len = strlen(message);
    size_t written = fwrite(message, 1, message_len, file);
    if (written != message_len) {
        perror("Write error");
        fclose(file);
        exit(EXIT_FAILURE);
    }

    rewind(file);

    char buffer[message_len + 1];
    size_t read = fread(buffer, 1, message_len, file);
    if (read != message_len) {
        perror("Read error");
        fclose(file);
        exit(EXIT_FAILURE);
    }
    buffer[read] = '\0';

    if (strcmp(message, buffer) != 0) {
        fprintf(stderr, "Verification failed: content mismatch\n");
        fclose(file);
        exit(EXIT_FAILURE);
    }

    fclose(file);
    return 0;
}
