        for (size_t i = 0; i < count; ++i) {
            if (i != 0) {
                output += ", ";
            }
            CIMValue element;
            value.getArrayElement(i, element);
            appendCIMValueToString(element, output);
        }
        output += "]";
    } else {
        output += value.toString();
    }
}

