void createImageProcessingGUI() {
    cv::namedWindow("Image Processing GUI", cv::WINDOW_AUTOSIZE);
    bool guiEnabled = true;
    bool unmskEnabled = false;
    bool unmskPlusEnabled = false;
    double gamma = 1.0;
    double fps = 0.0;
    cv::Mat displayImage(100, 400, CV_8UC3, cv::Scalar(0));

    cv::createTrackbar("UnMsk", "Image Processing GUI", nullptr, 1, [](int state, void* data) {
        *static_cast<bool*>(data) = state;
    }, &unmskEnabled);

    cv::createTrackbar("UnMsk.+", "Image Processing GUI", nullptr, 1, [](int state, void* data) {
        *static_cast<bool*>(data) = state;
    }, &unmskPlusEnabled);

    int gammaSlider = static_cast<int>((gamma - 0.2) * 100);
    cv::createTrackbar("UnMsk. Gamm", "Image Processing GUI", &gammaSlider, 130, [](int pos, void* data) {
        *static_cast<double*>(data) = 0.2 + pos * 0.01;
    }, &gamma);

    auto lastTime = std::chrono::high_resolution_clock::now();

    while (guiEnabled) {
        auto currentTime = std::chrono::high_resolution_clock::now();
        double elapsed = std::chrono::duration<double>(currentTime - lastTime).count();
        fps = 1.0 / elapsed;
        lastTime = currentTime;

        cv::setWindowTitle("Image Processing GUI", "Image Processing GUI - " + std::string(guiEnabled ? "[Enabled]" : "[Disabled]"));

        displayImage.setTo(cv::Scalar(0));
        std::string fpsText = "FPS: " + std::to_string(fps).substr(0, 4);
        cv::putText(displayImage, fpsText, cv::Point(10, 30), cv::FONT_HERSHEY_SIMPLEX, 0.7, cv::Scalar(255, 255, 255), 2);
        cv::imshow("Image Processing GUI", displayImage);

        int key = cv::waitKey(30);
        if (key == 27) {
            guiEnabled = false;
            cv::destroyWindow("Image Processing GUI");
        }
    }
}

