#include <CL/cl.h>
#include <vector>

std::vector<float> executeKernel(const std::vector<float>& input, const char* kernelSource, const char* kernelName) {
    cl_platform_id platform;
    clGetPlatformIDs(1, &platform, nullptr);

    cl_device_id device;
    clGetDeviceIDs(platform, CL_DEVICE_TYPE_DEFAULT, 1, &device, nullptr);

    cl_context context = clCreateContext(nullptr, 1, &device, nullptr, nullptr, nullptr);
    cl_command_queue queue = clCreateCommandQueue(context, device, 0, nullptr);

    size_t dataSize = input.size();
    size_t bufferSize = dataSize * sizeof(float);

    cl_mem inputBuffer = clCreateBuffer(context, CL_MEM_READ_ONLY | CL_MEM_COPY_HOST_PTR, bufferSize, (void*)input.data(), nullptr);
    cl_mem outputBuffer = clCreateBuffer(context, CL_MEM_WRITE_ONLY, bufferSize, nullptr, nullptr);
    cl_mem tempBuffer = clCreateBuffer(context, CL_MEM_READ_WRITE, bufferSize, nullptr, nullptr);

    cl_program program = clCreateProgramWithSource(context, 1, &kernelSource, nullptr, nullptr);
    clBuildProgram(program, 1, &device, nullptr, nullptr, nullptr);

    cl_kernel kernel = clCreateKernel(program, kernelName, nullptr);
    clSetKernelArg(kernel, 0, sizeof(cl_mem), &inputBuffer);
    clSetKernelArg(kernel, 1, sizeof(cl_mem), &outputBuffer);
    clSetKernelArg(kernel, 2, sizeof(cl_mem), &tempBuffer);

    size_t globalWorkSize = dataSize;
    clEnqueueNDRangeKernel(queue, kernel, 1, nullptr, &globalWorkSize, nullptr, 0, nullptr, nullptr);

    std::vector<float> output(dataSize);
    clEnqueueReadBuffer(queue, outputBuffer, CL_TRUE, 0, bufferSize, output.data(), 0, nullptr, nullptr);

    clReleaseKernel(kernel);
    clReleaseProgram(program);
    clReleaseMemObject(inputBuffer);
    clReleaseMemObject(outputBuffer);
    clReleaseMemObject(tempBuffer);
    clReleaseCommandQueue(queue);
    clReleaseContext(context);

    return output;
}

