void* load_sound(const char* dir_path, const char* filename, const char* ext, char** error) {
    char full_path[1024];
    snprintf(full_path, sizeof(full_path), "%s/%s.%s", dir_path, filename, ext);

    FILE* file = fopen(full_path, "rb");
    if (!file) {
        *error = "File not found";
        return NULL;
    }

    char magic[4];
    if (fread(magic, 1, 4, file) != 4 || memcmp(magic, "SND", 3) != 0) {
        fclose(file);
        *error = "Incorrect file format";
        return NULL;
    }

    fseek(file, 0, SEEK_END);
    long size = ftell(file);
    rewind(file);

    void* data = malloc(size);
    if (!data) {
        fclose(file);
        *error = "Memory allocation failed";
        return NULL;
    }

    if (fread(data, 1, size, file) != size) {
        free(data);
        fclose(file);
        *error = "Error reading file";
        return NULL;
    }

    fclose(file);
    *error = NULL;
    return data;
}
