using namespace std;

string kdf2_sha1(const string& password, const string& master_key, size_t output_length) {
    vector<unsigned char> derived;
    size_t iterations = (output_length + 19) / 20;
    derived.reserve(iterations * 20);

    for (size_t i = 1; i <= iterations; ++i) {
        unsigned char counter[4];
        counter[0] = (i >> 24) & 0xFF;
        counter[1] = (i >> 16) & 0xFF;
        counter[2] = (i >> 8) & 0xFF;
        counter[3] = i & 0xFF;

        string data = master_key + string(reinterpret_cast<char*>(counter), 4);

        unsigned char digest[20];
        HMAC(EVP_sha1(), 
             reinterpret_cast<const unsigned char*>(password.data()), 
             password.size(),
             reinterpret_cast<const unsigned char*>(data.data()), 
             data.size(),
             digest, 
             nullptr);

        derived.insert(derived.end(), digest, digest + 20);
    }

    derived.resize(output_length);
    return string(derived.begin(), derived.end());
}

