void* aligned_alloc_verify(size_t size) {
    size_t cache_line = sysconf(_SC_LEVEL1_DCACHE_LINESIZE);
    if (cache_line <= 0) cache_line = 64;

    size_t max_size = size > cache_line ? size : cache_line;
    size_t alignment = 1;
