bool files_identical(const char *path1, const char *path2) {
    FILE *fp1 = fopen(path1, "rb");
    FILE *fp2 = fopen(path2, "rb");
    if (!fp1 || !fp2) {
        if (fp1) fclose(fp1);
        if (fp2) fclose(fp2);
        return false;
    }

    int c1, c2;
    do {
        c1 = fgetc(fp1);
        c2 = fgetc(fp2);
        if (c1 != c2) {
            fclose(fp1);
            fclose(fp2);
            return false;
        }
    } while (c1 != EOF && c2 != EOF);

    bool same = (c1 == EOF && c2 == EOF);
    fclose(fp1);
    fclose(fp2);
    return same;
}
