void insertAfter(std::forward_list<std::string>& list, const std::string& firstStr, const std::string& secondStr) {
    auto prev = list.before_begin();
    auto curr = list.begin();
    while (curr != list.end()) {
        if (*curr == firstStr) {
            list.insert_after(curr, secondStr);
            return;
        }
        prev = curr;
        ++curr;
    }
    list.insert_after(prev, secondStr);
}
