int atomic_add(void* ptr, uint64_t value, uint32_t rkey, ibv_qp* qp) {
    ibv_send_wr wr = {};
    ibv_sge sge = {};
    ibv_send_wr* bad_wr = nullptr;
    uintptr_t addr = reinterpret_cast<uintptr_t>(ptr);

    wr.opcode = IBV_WR_ATOMIC_FETCH_AND_ADD;
    wr.num_sge = 1;
    wr.sg_list = &sge;
    wr.wr.atomic.remote_addr = addr;
    wr.wr.atomic.rkey = rkey;
    wr.wr.atomic.compare_add = value;

    if ((addr % 8) == 0) {
        sge.length = 8;
    } else if ((addr % 4) == 0) {
        sge.length = 4;
    } else {
        return EINVAL;
    }

    sge.addr = 0;
    sge.lkey = 0;

    return ibv_post_send(qp, &wr, &bad_wr);
}
