#include <stdio.h>
#include <stdlib.h>

wchar_t* read_unicode_file(const char* path) {
    FILE* file = fopen(path, "rb");
    if (!file) return NULL;

    if (fseek(file, 0, SEEK_END) != 0) {
        fclose(file);
        return NULL;
    }
    long size = ftell(file);
    if (size == -1) {
        fclose(file);
        return NULL;
    }
    rewind(file);

    char* buffer = malloc(size + 1);
    if (!buffer) {
        fclose(file);
        return NULL;
    }
    size_t read = fread(buffer, 1, size, file);
    if (read != size) {
        free(buffer);
        fclose(file);
        return NULL;
    }
    buffer[read] = '\0';
    fclose(file);

    char* locale = setlocale(LC_CTYPE, "en_US.UTF-8");
    if (!locale) {
        free(buffer);
        return NULL;
    }

    size_t wlen = mbstowcs(NULL, buffer, 0);
    if (wlen == (size_t)-1) {
        free(buffer);
        return NULL;
    }
    wchar_t* wstr = malloc((wlen + 1) * sizeof(wchar_t));
    if (!wstr) {
        free(buffer);
        return NULL;
    }
    mbstowcs(wstr, buffer, wlen + 1);
    free(buffer);
    return wstr;
}
