void generate_config_string(VideoConfig *config, void (*log_func)(const char*)) {
    char buffer[512];
    int gcd_val = gcd(config->width, config->height);
    int aspect_w = config->width / gcd_val;
    int aspect_h = config->height / gcd_val;
    int frame_count = (int)(config->frame_rate * config->encoding_params.duration + 0.5f);
    int seek_frames = frame_count / config->encoding_params.keyframe_interval;

    snprintf(buffer, sizeof(buffer),
        "Video Config: %dx%d@%.2f\nAspect Ratio: %d:%d\nFrames: %d\nSeek Points: %d\n",
        config->width, config->height, config->frame_rate, aspect_w, aspect_h,
        frame_count, seek_frames);

    log_func(buffer);
}
