#include <string>
#include <vector>

struct Option {
    std::string name;
    std::string value;
};

int parseOptions(const std::string& input, Option* options, int maxOptions) {
    std::vector<std::string> parts;
    size_t start = 0;
    size_t end = input.find(',');

    while (end != std::string::npos) {
        std::string part = input.substr(start, end - start);
        if (part.empty()) return -1;
        parts.push_back(part);
        start = end + 1;
        end = input.find(',', start);
    }

    std::string lastPart = input.substr(start);
    if (lastPart.empty()) return -1;
    parts.push_back(lastPart);

    if (parts.size() % 2 != 0) return -1;
    int numOptions = parts.size() / 2;
    if (numOptions > maxOptions) return -1;

    for (int i = 0; i < numOptions; ++i) {
        options[i].name = parts[2 * i];
        options[i].value = parts[2 * i + 1];
    }

    return numOptions;
}
