        components[0] = url.substr(0, protocol_end);
        protocol_end += 3;
    } else {
        components[0] = "";
        protocol_end = 0;
    }
    string rest = url.substr(protocol_end);
    size_t colon_slash = rest.find_first_of(":/");
    if (colon_slash == string::npos) {
        components[1] = rest;
        components[2] = "";
    } else {
        components[1] = rest.substr(0, colon_slash);
        if (rest[colon_slash] == ':') {
            size_t port_end = rest.find('/', colon_slash + 1);
            components[2] = rest.substr(colon_slash + 1, port_end - (colon_slash + 1));
        } else {
            components[2] = "";
        }
    }
    return components;
}
