#include <boost/beast.hpp>
#include <boost/asio.hpp>
#include <memory>
#include <iostream>

namespace beast = boost::beast;
namespace http = beast::http;
namespace net = boost::asio;
using tcp = net::ip::tcp;

class InterfaceTable {
public:
    virtual bool FindVmUuidFromMetadataIp(const std::string&) { return false; }
    virtual ~InterfaceTable() = default;
};

class MockInterfaceTable : public InterfaceTable {
public:
    bool FindVmUuidFromMetadataIp(const std::string&) override { return true; }
};

class SandeshClient {
    std::unique_ptr<InterfaceTable> interface_table_;
    int requests_ = 0;
    int proxy_sessions_ = 0;
    int internal_errors_ = 0;

public:
    SandeshClient(std::unique_ptr<InterfaceTable> it) : interface_table_(std::move(it)) {}

    void execute_request(const std::string& host, const std::string& port) {
        try {
            if (!interface_table_->FindVmUuidFromMetadataIp("dummy_ip")) {
                internal_errors_++;
                return;
            }

            net::io_context ioc;
            tcp::resolver resolver(ioc);
            beast::tcp_stream stream(ioc);

            auto const results = resolver.resolve(host, port);
            stream.connect(results);

            http::request<http::string_body> req{http::verb::get, "/", 11};
            req.set(http::field::host, host);

            http::write(stream, req);

            beast::flat_buffer buffer;
            http::response<http::string_body> res;
            http::read(stream, buffer, res);

            requests_++;
            proxy_sessions_++;

            if (res.result() != http::status::ok || res.body() != "expected") {
                internal_errors_++;
            }

            stream.socket().shutdown(tcp::socket::shutdown_both);
        } catch (...) {
            internal_errors_++;
        }
    }

    void print_stats() const {
        std::cout << "Requests: " << requests_ << "\n"
                  << "Proxy Sessions: " << proxy_sessions_ << "\n"
                  << "Internal Errors: " << internal_errors_ << "\n";
    }
};

int main() {
    SandeshClient client(std::make_unique<MockInterfaceTable>());
    client.execute_request("localhost", "8080");
    client.print_stats();
    return 0;
}

