int loadRobotFromFile(const string& filename) {
    size_t dotPos = filename.find_last_of('.');
    string identifier = (dotPos != string::npos) ? filename.substr(0, dotPos) : filename;

    ifstream file(filename);
    if (!file.is_open()) return -1;

    Robot robot;
    robot.setIdentifier(identifier);

    if (!robot.load(file)) {
        file.close();
        return -1;
    }
    file.close();

    robots.push_back(robot);
    return robots.size() - 1;
}

