#include <iostream>
#include <fstream>
using namespace std;

void linearRegression(double x[], double y[], int n, double& m, double& b) {
    double sum_x = 0, sum_y = 0, sum_xy = 0, sum_x2 = 0;
    for (int i = 0; i < n; ++i) {
        sum_x += x[i];
        sum_y += y[i];
        sum_xy += x[i] * y[i];
        sum_x2 += x[i] * x[i];
    }
    m = (n * sum_xy - sum_x * sum_y) / (n * sum_x2 - sum_x * sum_x);
    b = (sum_y - m * sum_x) / n;
}

int main() {
    ifstream file("data.txt");
    if (!file.is_open()) {
        cerr << "Error opening file." << endl;
        return 1;
    }

    int n = 0;
    double temp_x, temp_y;
    while (file >> temp_x >> temp_y) n++;

    if (n == 0) {
        cerr << "No data points found." << endl;
        return 1;
    }

    file.clear();
    file.seekg(0);

    double* x = new double[n];
    double* y = new double[n];

    for (int i = 0; i < n; ++i)
        file >> x[i] >> y[i];
    file.close();

    double m, b;
    linearRegression(x, y, n, m, b);

    cout << "Number of data points: " << n << endl;
    cout << "Regression coefficients: slope = " << m << ", intercept = " << b << endl;

    delete[] x;
    delete[] y;
    return 0;
}

