struct AllocationRecord {
    void* ptr;
    size_t size;
};

class TestAllocator {
public:
    TestAllocator() = default;

    char* allocate(size_t size) {
        char* ptr = static_cast<char*>(malloc(size));
        if (ptr) {
            allocations.push_back({ptr, size});
        }
        return ptr;
    }

    void deallocate(char* ptr) {
        auto it = std::find_if(allocations.begin(), allocations.end(), [ptr](const AllocationRecord& rec) {
            return rec.ptr == ptr;
        });
        if (it != allocations.end()) {
            free(ptr);
            allocations.erase(it);
        }
    }

    const std::vector<AllocationRecord>& getAllocations() const {
        return allocations;
    }

private:
    std::vector<AllocationRecord> allocations;
};

int main(int argc, char* argv[]) {
    bool verbose = false;
    if (argc > 1) {
        std::string arg = argv[1];
        verbose = (arg == "-v" || arg == "--verbose");
    }

    TestAllocator allocator;
    std::vector<size_t> sizes = {100, 200, 300, 500, 1024};
    std::vector<char*> buffers;

    for (auto size : sizes) {
        char* buf = allocator.allocate(size);
        if (buf) buffers.push_back(buf);
        else std::cerr << "Allocation failed for size " << size << std::endl;
    }

    const auto& allocs = allocator.getAllocations();
    if (verbose) {
        std::cout << "Allocated blocks: " << allocs.size() << "\n";
        for (size_t i = 0; i < allocs.size(); ++i) {
            std::cout << "Block " << i+1 << ": Address=0x" << allocs[i].ptr 
                      << ", Size=" << allocs[i].size << " bytes\n";
        }
    } else {
        for (const auto& a : allocs) {
            std::cout << "0x" << a.ptr << " " << a.size << "\n";
        }
    }

    for (auto buf : buffers) {
        allocator.deallocate(buf);
    }

    return 0;
}

