void computeEigen(int** matrix, int rows, int cols, double** eigenvalues, double*** eigenvectors, int* nonZeroCount, double* minEigen, double* maxEigen) {
    if (rows != cols) {
        *eigenvalues = nullptr;
        *eigenvectors = nullptr;
        *nonZeroCount = 0;
        *minEigen = *maxEigen = 0;
        return;
    }

    int n = rows;
    *nonZeroCount = 0;
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            if (matrix[i][j] != 0) (*nonZeroCount)++;
        }
    }

    MatrixXd eigenMatrix(n, n);
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            eigenMatrix(i, j) = matrix[i][j];
        }
    }

    SelfAdjointEigenSolver<MatrixXd> solver(eigenMatrix);
    if (solver.info() != Success) {
        *eigenvalues = nullptr;
        *eigenvectors = nullptr;
        *minEigen = *maxEigen = 0;
        return;
    }

    VectorXd evals = solver.eigenvalues();
    MatrixXd evecs = solver.eigenvectors();

    *eigenvalues = new double[n];
    for (int i = 0; i < n; ++i) {
        (*eigenvalues)[i] = evals(i);
    }

    *eigenvectors = new double*[n];
    for (int i = 0; i < n; ++i) {
        (*eigenvectors)[i] = new double[n];
        for (int j = 0; j < n; ++j) {
            (*eigenvectors)[i][j] = evecs(j, i);
        }
    }

    *minEigen = evals.minCoeff();
    *maxEigen = evals.maxCoeff();
}

