class AnsiString {
    char* data;
public:
    AnsiString(const char* str = nullptr) : data(nullptr) {
        if (str) {
            data = new char[std::strlen(str) + 1];
            std::strcpy(data, str);
        }
    }
    ~AnsiString() { delete[] data; }
    AnsiString(const AnsiString& other) : data(nullptr) {
        if (other.data) {
            data = new char[std::strlen(other.data) + 1];
            std::strcpy(data, other.data);
        }
    }
    AnsiString& operator=(const AnsiString& other) {
        if (this != &other) {
            delete[] data;
            data = other.data ? new char[std::strlen(other.data) + 1] : nullptr;
            if (data) std::strcpy(data, other.data);
        }
        return *this;
    }
    friend AnsiString operator+(const AnsiString& lhs, const AnsiString& rhs) {
        size_t lhsLen = lhs.data ? std::strlen(lhs.data) : 0;
        size_t rhsLen = rhs.data ? std::strlen(rhs.data) : 0;
        char* buffer = new char[lhsLen + rhsLen + 1];
        if (lhs.data) std::strcpy(buffer, lhs.data);
        if (rhs.data) std::strcpy(buffer + lhsLen, rhs.data);
        AnsiString result;
        result.data = buffer;
        return result;
    }
    friend bool operator==(const AnsiString& lhs, const AnsiString& rhs) {
        if (lhs.data == rhs.data) return true;
        if (!lhs.data || !rhs.data) return false;
        return std::strcmp(lhs.data, rhs.data) == 0;
    }
};

