    AudioComponent comp = AudioComponentFindNext(nullptr, &desc);
    if (!comp) return kAudioUnitErr_InvalidComponent;

    status = AudioComponentInstanceNew(comp, &audioUnit);
    if (status != noErr) return status;

    UInt32 bufferSize = 4096;
    buffer = (Float32*)malloc(bufferSize * sizeof(Float32));
    if (!buffer) {
        AudioComponentInstanceDispose(audioUnit);
        return kAudio_MemFullError;
    }

    AudioStreamBasicDescription asbd = {0};
    asbd.mSampleRate = sampleRate;
    asbd.mFormatID = kAudioFormatLinearPCM;
    asbd.mFormatFlags = kAudioFormatFlagIsFloat | kAudioFormatFlagIsPacked;
    asbd.mChannelsPerFrame = 2;
    asbd.mFramesPerPacket = 1;
    asbd.mBitsPerChannel = 32;
    asbd.mBytesPerPacket = asbd.mChannelsPerFrame * sizeof(Float32);
    asbd.mBytesPerFrame = asbd.mChannelsPerFrame * sizeof(Float32);

    status = AudioUnitSetProperty(audioUnit, kAudioUnitProperty_StreamFormat, kAudioUnitScope_Input, 0, &asbd, sizeof(asbd));
    if (status != noErr) {
        free(buffer);
        AudioComponentInstanceDispose(audioUnit);
        return status;
    }

    status = AudioUnitInitialize(audioUnit);
    if (status != noErr) {
        free(buffer);
        AudioComponentInstanceDispose(audioUnit);
        return status;
    }

    status = AudioUnitReset(audioUnit, kAudioUnitScope_Global, 0);
    if (status != noErr) {
        free(buffer);
        AudioComponentInstanceDispose(audioUnit);
        return status;
    }

    return noErr;
}
