#include <stdlib.h>
#include <stdio.h>
#include <wchar.h>
#include <locale.h>

wchar_t* read_file_to_unicode(const char* path) {
    FILE* file = fopen(path, "rb");
    if (!file) return NULL;

    if (fseek(file, 0, SEEK_END) != 0) {
        fclose(file);
        return NULL;
    }
    long file_size = ftell(file);
    if (file_size == -1) {
        fclose(file);
        return NULL;
    }
    rewind(file);

    char* buffer = malloc(file_size + 1);
    if (!buffer) {
        fclose(file);
        return NULL;
    }

    size_t read_size = fread(buffer, 1, file_size, file);
    if (read_size != (size_t)file_size) {
        free(buffer);
        fclose(file);
        return NULL;
    }
    buffer[read_size] = '\0';
    fclose(file);

    setlocale(LC_CTYPE, "");
    size_t wc_size = mbstowcs(NULL, buffer, 0);
    if (wc_size == (size_t)-1) {
        free(buffer);
        return NULL;
    }

    wchar_t* wstr = malloc((wc_size + 1) * sizeof(wchar_t));
    if (!wstr) {
        free(buffer);
        return NULL;
    }

    if (mbstowcs(wstr, buffer, wc_size + 1) == (size_t)-1) {
        free(buffer);
        free(wstr);
        return NULL;
    }

    free(buffer);
    return wstr;
}
