} CRC_INDICATION_REL8_TAG;

typedef struct NFAPI_CRC_INDICATION_PDU_T {
    RX_UE_INFORMATION_TAG rx_ue_info;
    CRC_INDICATION_REL8_TAG crc_indication_rel8;
    struct NFAPI_CRC_INDICATION_PDU_T* next;
} NFAPI_CRC_INDICATION_PDU_T;

NFAPI_CRC_INDICATION_PDU_T* create_crc_indication_list(int count) {
    if (count <= 0) return NULL;

    NFAPI_CRC_INDICATION_PDU_T *head = NULL, *prev = NULL;
    srand(time(NULL));

    for (int i = 0; i < count; ++i) {
        NFAPI_CRC_INDICATION_PDU_T *current = malloc(sizeof(NFAPI_CRC_INDICATION_PDU_T));
        if (!current) {
            while (head) {
                NFAPI_CRC_INDICATION_PDU_T *tmp = head;
                head = head->next;
                free(tmp);
            }
            return NULL;
        }

        current->rx_ue_info.RNTI = (unsigned short)(rand() & 0xFFFF);
        current->crc_indication_rel8.CRCFLAG = rand() % 2;
        current->next = NULL;

        if (prev) {
            prev->next = current;
        } else {
            head = current;
        }
        prev = current;
    }

    return head;
}
