int knnRadiusSearch(const std::vector<std::array<float, 3>>& points, const std::array<float, 3>& query, int k, float radius) {
    std::vector<float> dataset_data;
    dataset_data.reserve(points.size() * 3);
    for (const auto& p : points) {
        dataset_data.push_back(p[0]);
        dataset_data.push_back(p[1]);
        dataset_data.push_back(p[2]);
    }
    flann::Matrix<float> dataset(dataset_data.data(), points.size(), 3);

    flann::Index<flann::L2<float>> index(dataset, flann::KDTreeSingleIndexParams());
    index.buildIndex();

    std::vector<float> query_data = {query[0], query[1], query[2]};
    flann::Matrix<float> query_point(query_data.data(), 1, 3);

    std::vector<int> indices_data(k);
    std::vector<float> distances_data(k);
    flann::Matrix<int> indices(indices_data.data(), 1, k);
    flann::Matrix<float> distances(distances_data.data(), 1, k);

    int num_found = index.knnSearch(query_point, indices, distances, k, flann::SearchParams());

    int count = 0;
    float radius_sq = radius * radius;
    for (int i = 0; i < num_found; ++i) {
        if (distances_data[i] <= radius_sq) {
            ++count;
        }
    }

    return count;
}
