typedef struct {
    int value;
    int index;
} EntryInfo;

int compare_entries(const void* a, const void* b) {
    const EntryInfo* ea = (const EntryInfo*)a;
    const EntryInfo* eb = (const EntryInfo*)b;
    return ea->value - eb->value;
}

int dedup_and_sort(int* entries, int n, int** result) {
    if (n == 0) {
        *result = NULL;
        return 0;
    }
    EntryInfo* unique_entries = malloc(n * sizeof(EntryInfo));
    int unique_count = 0;
    for (int i = 0; i < n; i++) {
        int current = entries[i];
        int found = 0;
        for (int j = 0; j < unique_count; j++) {
            if (unique_entries[j].value == current) {
                found = 1;
                break;
            }
        }
        if (!found) {
            unique_entries[unique_count].value = current;
            unique_entries[unique_count].index = i;
            unique_count++;
        }
    }
    qsort(unique_entries, unique_count, sizeof(EntryInfo), compare_entries);
    *result = malloc(unique_count * sizeof(int));
    for (int i = 0; i < unique_count; i++) {
        (*result)[i] = unique_entries[i].index;
    }
    free(unique_entries);
    return unique_count;
}
