int calculate_ways(int n, int k) {
    static int memo[100][100];
    static int initialized = 0;
    if (!initialized) {
        for (int i = 0; i < 100; i++)
            for (int j = 0; j < 100; j++)
                memo[i][j] = -1;
        initialized = 1;
    }
    if (k == 0) return 1;
    if (n < k) return 0;
    if (k == n) return 1 << n;
    if (memo[n][k] != -1) return memo[n][k];
    memo[n][k] = calculate_ways(n-1, k) + 2 * calculate_ways(n-1, k-1);
    return memo[n][k];
}
