const char* aggregate(int key, const int* list, size_t n) {
    static char buffer[256];
    size_t used = 0;
    int written;

    written = snprintf(buffer, sizeof(buffer), "AGGREGATED-OUTPUT[%d]:", key);
    if (written >= sizeof(buffer)) {
        snprintf(buffer, sizeof(buffer), "ERROR: Buffer too small");
        return buffer;
    }
    used = written;

    for (size_t i = 0; i < n; ++i) {
        size_t remaining = sizeof(buffer) - used;
        written = snprintf(buffer + used, remaining, " %d", list[i]);
        if (written >= remaining) {
            snprintf(buffer, sizeof(buffer), "ERROR: Buffer too small");
            return buffer;
        }
        used += written;
    }

    return buffer;
}
