using namespace std;

enum class InputType { DENSE, SPARSE, SEQUENCE };

vector<vector<vector<float>>> create_input_data(InputType type, int batch_size, const vector<int>& input_dims, float sparsity = 0.5f) {
    if ((type == InputType::DENSE || type == InputType::SPARSE) && input_dims.size() != 1) {
        throw invalid_argument("For DENSE/SPARSE, input_dims must have 1 element.");
    }
    if (type == InputType::SEQUENCE && input_dims.size() != 2) {
        throw invalid_argument("For SEQUENCE, input_dims must have 2 elements.");
    }

    int features = input_dims[0];
    int time_steps = 1;
    if (type == InputType::SEQUENCE) {
        time_steps = input_dims[0];
        features = input_dims[1];
    }

    random_device rd;
    mt19937 gen(rd());
    uniform_real_distribution<float> dist(0.0f, 1.0f);
    uniform_real_distribution<float> prob(0.0f, 1.0f);

    vector<vector<vector<float>>> matrix(batch_size);

    for (int i = 0; i < batch_size; ++i) {
        matrix[i].resize(time_steps);
        for (int t = 0; t < time_steps; ++t) {
            matrix[i][t].resize(features);
            for (int f = 0; f < features; ++f) {
                if (type == InputType::SPARSE) {
                    if (prob(gen) < sparsity) {
                        matrix[i][t][f] = 0.0f;
                    } else {
                        matrix[i][t][f] = dist(gen);
                    }
                } else {
                    matrix[i][t][f] = dist(gen);
                }
            }
        }
    }

    return matrix;
}

