int parse_blocks(const char *filename, int **indices) {
    FILE *file = fopen(filename, "rb");
    if (!file) {
        *indices = NULL;
        return 0;
    }

    int count;
    if (fread(&count, sizeof(int), 1, file) != 1) {
        fclose(file);
        *indices = NULL;
        return 0;
    }

    if (count <= 0) {
        *indices = NULL;
        fclose(file);
        return count;
    }

    *indices = malloc(count * sizeof(int));
    if (!*indices) {
        fclose(file);
        return -2;
    }

    fread(*indices, sizeof(int), count, file);
    fclose(file);
    return count;
}
