#include <librealsense2/rs.hpp>
#include <ros/ros.h>
#include <sensor_msgs/PointCloud2.h>
#include <sensor_msgs/Image.h>
#include <image_transport/image_transport.h>
#include <cv_bridge/cv_bridge.h>
#include <rs2_ros/points.h>

void setupRealsense(ros::NodeHandle& nh) {
    rs2::pipeline pipe;
    rs2::config cfg;
    cfg.enable_stream(RS2_STREAM_COLOR, 640, 480, RS2_FORMAT_BGR8, 30);
    cfg.enable_stream(RS2_STREAM_DEPTH, 640, 480, RS2_FORMAT_Z16, 30);
    pipe.start(cfg);

    image_transport::ImageTransport it(nh);
    auto rgb_pub = it.advertise("camera/rgb", 1);
    auto depth_pub = it.advertise("camera/depth", 1);
    auto pc_pub = nh.advertise<sensor_msgs::PointCloud2>("camera/points", 1);

    rs2::pointcloud pc;
    rs2::align align_to_color(RS2_STREAM_COLOR);

    while (ros::ok()) {
        rs2::frameset frames = pipe.wait_for_frames();
        frames = align_to_color.process(frames);

        rs2::video_frame color_frame = frames.get_color_frame();
        rs2::depth_frame depth_frame = frames.get_depth_frame();
        rs2::points points = pc.calculate(depth_frame);

        cv::Mat rgb(cv::Size(640, 480), CV_8UC3, (void*)color_frame.get_data());
        cv::Mat depth(cv::Size(640, 480), CV_16UC1, (void*)depth_frame.get_data());

        sensor_msgs::ImagePtr rgb_msg = cv_bridge::CvImage(std_msgs::Header(), "bgr8", rgb).toImageMsg();
        sensor_msgs::ImagePtr depth_msg = cv_bridge::CvImage(std_msgs::Header(), "mono16", depth).toImageMsg();

        rgb_pub.publish(rgb_msg);
        depth_pub.publish(depth_msg);

        sensor_msgs::PointCloud2 cloud_msg;
        cloud_msg.header.stamp = ros::Time::now();
        cloud_msg.header.frame_id = "camera_link";
        cloud_msg.height = depth_frame.get_height();
        cloud_msg.width = depth_frame.get_width();
        cloud_msg.is_dense = false;

        auto vertices = points.get_vertices();
        cloud_msg.point_step = sizeof(float) * 4;
        cloud_msg.row_step = cloud_msg.point_step * cloud_msg.width;
        cloud_msg.data.resize(cloud_msg.row_step * cloud_msg.height);
        cloud_msg.fields = {
            {"x", 0, sensor_msgs::PointField::FLOAT32, 1},
            {"y", 4, sensor_msgs::PointField::FLOAT32, 1},
            {"z", 8, sensor_msgs::PointField::FLOAT32, 1},
            {"rgb", 12, sensor_msgs::PointField::FLOAT32, 1}
        };

        float* cloud_data = (float*)cloud_msg.data.data();
        for (int i = 0; i < points.size(); ++i) {
            cloud_data[i*4] = vertices[i].x;
            cloud_data[i*4+1] = vertices[i].y;
            cloud_data[i*4+2] = vertices[i].z;
            cloud_data[i*4+3] = *reinterpret_cast<float*>(&rgb.data[i*3]);
        }

        pc_pub.publish(cloud_msg);
    }
}

