#include <vector>
#include <unordered_map>

using namespace std;

class DisjointSetUnion {
private:
    unordered_map<int, int> parent;
    unordered_map<int, int> rank;

public:
    int find(int x) {
        if (!parent.count(x)) {
            parent[x] = x;
            rank[x] = 1;
        }
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    void unite(int x, int y) {
        int xRoot = find(x);
        int yRoot = find(y);
        if (xRoot == yRoot) return;
        if (rank[xRoot] < rank[yRoot]) {
            parent[xRoot] = yRoot;
        } else {
            parent[yRoot] = xRoot;
            if (rank[xRoot] == rank[yRoot]) {
                rank[xRoot]++;
            }
        }
    }
};

bool checkPairwiseConnected(const vector<int>& first, const vector<int>& second) {
    DisjointSetUnion dsu;

    if (first.empty()) {
        return second.empty();
    }

    int root = first[0];
    for (int num : first) {
        dsu.find(num);
        dsu.unite(root, num);
    }

    int firstRoot = dsu.find(root);
    for (int num : second) {
        if (dsu.find(num) != firstRoot) {
            return false;
        }
    }

    return true;
}
