#include <stdio.h>
#include <stdlib.h>

void update_max_pieces(const char *filename, int *max_value) {
    FILE *file = fopen(filename, "r");
    if (!file) return;

    if (fseek(file, 0, SEEK_END) != 0) {
        fclose(file);
        return;
    }

    long length = ftell(file);
    if (length == -1) {
        fclose(file);
        return;
    }

    rewind(file);
    char *buffer = malloc(length + 1);
    if (!buffer) {
        fclose(file);
        return;
    }

    size_t bytes_read = fread(buffer, 1, length, file);
    fclose(file);
    if (bytes_read != (size_t)length) {
        free(buffer);
        return;
    }
    buffer[bytes_read] = '\0';

    int count = 0;
    for (char *p = buffer; *p; ++p) {
        if (*p == '\n') count++;
    }

