void format_message(const char *format, va_list args, void (*callback)(const char *)) {
    char buffer[256];
    va_list args_copy;
    va_copy(args_copy, args);
    int needed = vsnprintf(buffer, sizeof(buffer), format, args_copy);
    va_end(args_copy);

    if (needed < 0) {
        callback("");
        return;
    }

    if (needed < (int)sizeof(buffer)) {
        callback(buffer);
    } else {
        char *dynamic_buffer = malloc(needed + 1);
        if (dynamic_buffer) {
            va_list args_copy2;
            va_copy(args_copy2, args);
            vsnprintf(dynamic_buffer, needed + 1, format, args_copy2);
            va_end(args_copy2);
            callback(dynamic_buffer);
            free(dynamic_buffer);
        } else {
            callback(buffer);
        }
    }
}
