struct OutputCount {
    int value;
    int depth;
};

list<OutputCount> process(const map<int, OutputCount>& stats, const list<int>& counts) {
    vector<OutputCount> temp;
    for (int id : counts) {
        auto it = stats.find(id);
        if (it != stats.end()) {
            temp.push_back(it->second);
        }
    }
    sort(temp.begin(), temp.end(), [](const OutputCount& a, const OutputCount& b) {
        if (a.value == b.value) {
            return a.depth < b.depth;
        }
        return a.value > b.value;
    });
    return list<OutputCount>(temp.begin(), temp.end());
}

